INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
('real-estate-moex-00769', 'real-estate', 'real-estate-moex-107-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '公平交易委員會發現某甲事業可能有違法之聯合行為情事，依職權欲對甲事業調查處理。關於調 查之事項，下列何者錯誤？', '["派員前往當事人及關係人之事務所、營業所或其他場所為必要之調查", "甲事業若承諾在主管機關所定期限內，採取具體措施停止並改正涉有違法之行為者，主管機關 得中止調查", "執行調查之人員依法執行公務時，未出示有關執行職務之證明文件者，受調查者得拒絕之", "調查所得可為證據之物，主管機關得扣留之；其扣留範圍及期間，不以供調查、檢驗、鑑定或 其他為保全證據之目的所必要者為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "d0496d6e0e1d", "answer_pdf_sha1": "c25bacc97ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00770', 'real-estate', 'real-estate-moex-107-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '甲為一位知名影星，曾拍攝二個不動產廣告，且知悉該等廣告有不實的情形。在成名之前，甲接拍 廣告主乙的不動產廣告，廣告中反映甲對不動產商品的信賴，結果當時消費者丙即曾經檢舉廣告不 實。十二年之後，甲已成為知名公眾人物，接了第二個廣告主丁的不動產廣告，反映甲對該廣告商 品的親身體驗。此時，消費者戊檢舉廣告不實。依公平交易法之規定，下列敘述，何者正確？', '["甲必須是「明知」其所從事之薦證有引人錯誤之虞，而仍為薦證，才需要負責", "第一個廣告，甲仍非知名公眾人物，僅於受乙報酬五倍之範圍內，與乙負連帶損害賠償責任", "第二個廣告，甲為知名人士，須與丁負連帶損害賠償責任", "丙和戊的請求權尚未超過法定期限，故其請求權尚未消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "d0496d6e0e1d", "answer_pdf_sha1": "c25bacc97ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00771', 'real-estate', 'real-estate-moex-107-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '消費者保護法關於企業經營者對於廣告內容之規定，下列何者正確？', '["製作廣告之媒體經營者應確保廣告內容之真實，其對消費者所負之義務不得低於廣告之內容", "企業經營者對消費者從事與分期付款買賣有關之交易時，應於廣告上明示應付所有總費用之年 百分率", "刊登或報導廣告之媒體經營者明知或可得而知廣告內容與事實不符者，就消費者因信賴該廣告 所受之損害與企業經營者負連帶責任", "企業經營者得預先約定限縮信賴該廣告之賠償責任範圍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "d0496d6e0e1d", "answer_pdf_sha1": "c25bacc97ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00772', 'real-estate', 'real-estate-moex-107-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '消費者保護團體得依消費者保護法之規定，提起消費者損害賠償訴訟或不作為訴訟，下列何者錯誤？', '["消費者保護團體依規定提起訴訟者，得以自己之名義提起，視個案情形決定是否委任律師代理訴訟", "消費者保護團體對於同一之原因事件，致使眾多消費者受害時，得受讓二十人以上消費者損害 賠償請求權後，以自己名義，提起訴訟", "消費者保護團體以自己名義提起訴訟者，應具備之條件有：許可設立二年以上，置有消費者保 護專門人員，且申請行政院評定優良", "消費者保護團體以自己之名義提起消費者損害賠償訴訟，其標的價額超過新臺幣六十萬元者， 超過部分免繳裁判費"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "d0496d6e0e1d", "answer_pdf_sha1": "c25bacc97ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00773', 'real-estate', 'real-estate-moex-107-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '當有事實證明該流通進入市場之商品或服務，具有危害消費者安全與健康之虞時，為避免消費者 權益遭受損害，企業經營者應回收或停止該有危險之商品或服務，以防免發生或擴大損害。依消 費者保護法之規定，下列何者錯誤？', '["中央主管機關認為有必要時，得命有損害消費者生命、身體、健康或財產的企業經營者立即停 止該商品之設計、生產、製造、加工、輸入、經銷或服務之提供，或採取其他必要措施", "直轄市或縣（市）政府對於企業經營者提供之商品或服務，經調查認為確有損害消費者生命、 身體、健康或財產，或確有損害之虞者，應命其限期改善、回收或銷燬", "企業經營者於有事實足認其提供之商品或服務有危害消費者安全與健康之虞時，於明顯處為警 告標示，得免除回收該批商品或停止其服務之責任", "直轄市或縣（市）政府於企業經營者提供之商品或服務，對消費者已發生重大損害或有發生重 大損害之虞，而情況危急時，應即在大眾傳播媒體公告企業經營者之名稱、地址、商品、服務、 或為其他必要之處置"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "d0496d6e0e1d", "answer_pdf_sha1": "c25bacc97ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
